Here's an example of how you might use `useCallback` in a React component:

```jsx
import { useState, useCallback } from 'react';

const ExampleComponent = () => {
  const [count, setCount] = useState(0);

  // This function will be recreated on every render
  const handleIncrement = () => {
    setCount(count + 1);
  };

  // This function will be memoized and only recreated when the dependencies change
  const memoizedHandleIncrement = useCallback(() => {
    setCount(count + 1);
  }, [count]);

  return (
    <div>
      <p>Count: {count}</p>
      <button onClick={handleIncrement}>Increment (not memoized)</button>
      <button onClick={memoizedHandleIncrement}>Increment (memoized)</button>
    </div>
  );
};
