using System.Collections;
using System.Collections.Generic;
using UnityEngine;

public class PlayerMovement : MonoBehaviour
{
    public float speed = 5.0f;
    public float turnSpeed = 5.0f;

    private Rigidbody rb;

    void Start()
    {
        rb = GetComponent<Rigidbody>();
    }

    void FixedUpdate()
    {
        // Move the cube forward
        float moveForward = Input.GetAxis("Vertical");
        Vector3 movement = transform.forward * moveForward * speed;

        // Turn the cube
        float turn = Input.GetAxis("Horizontal");
        Vector3 turnDirection = new Vector3(turn, 0, 0);
        Quaternion turnRotation = Quaternion.Euler(turnDirection * turnSpeed);

        // Apply movement and rotation
        rb.MovePosition(transform.position + movement * Time.deltaTime);
        transform.rotation = transform.rotation * turnRotation;
    }
}
```

In this script, the `FixedUpdate()` method is used instead of `Update()` because `FixedUpdate()` is called at a fixed rate (the same rate as the physics engine), which is more suitable for physics-related code like movement and rotation.

